issue_comment_body:
One more update. I have fixed the problem with the cleanup routine and the segmentation fault when using more than 1024 sids (I uploaded the new package to npm). 

The following script is stable:

```javascript
  var sidCount = 1024;
  var counters = new Array(sidCount).fill(0);
  var side = Math.ceil(Math.sqrt(sidCount));
  function printCounters() {
    for(var i = 0; i < side; i++) {
      var start = i * side;
      process.stdout.write('|' + counters.slice(start, start + side - 1).join(' ') + '|\n');
    }
  }

  with(d.flowchart('test')) {
    with(stage('start')) {
      to('action').whenAll(m.command.eq('start'));
    }

    with(stage('action')) {
      run(function(c) {
        c.s.count = (c.s.count ? c.s.count + 1: 1);
        counters[c.s.sid] = c.s.count;
        if(c.s.sid === 0) {
          console.log(Date() + ': Fired action for sid[' + c.s.sid + ']');
          printCounters();
        }
        c.post({id: 'p_' + c.s.count, sid: c.s.sid, command: 'await'});
      });
      to('await').whenAll(m.command.eq('await'));
    }

    with(stage('await')) {
      run(function(c) {
        c.startTimer('timeout', 1, 't_' + c.s.count);
      });
      to('action').whenAll(timeout('timeout'));
    }

    whenStart(function (host) {
      for(var i = 0; i < sidCount; i++) {
        host.post('test', {id: sidCount, sid: i, command: 'start'});
      }
    })
  }

  d.runAll();
```  
Also to test the limits I tried the following script (16 processes and 8 redis instances):  
```javascript
var d = require('durable');
var cluster = require('cluster');
if (cluster.isMaster) {
     for (var j = 0; j < 16; j++) {
         cluster.fork();
     }

     cluster.on("exit", function (worker, code, signal) {
         cluster.fork();
     });
} else {

    var sidCount = 11000;
    function printCounters(host) {
        var avg = 0;
        for (var i = 0; i < sidCount; i++) {
          avg += host.getState('test', i).count;
        } 
        
        avg /= sidCount;
        console.log('average : ' + avg);
        
        var stdv = 0;
        for (var i = 0; i < sidCount; i++) {
          stdv += Math.pow(host.getState('test', i).count - avg, 2);
        }

        stdv /= sidCount;
        stdv = Math.sqrt(stdv);
        console.log('standard deviation : ' + stdv);
    }

    with(d.ruleset('test')) {
        whenAll(m.command.eq('start').or(timeout('timeout')), function(c) {
            if (c.m.command === 'start') {
                c.s.count = 0;
            } else {
                c.s.count += 1;
                if (c.s.sid === 0 && c.s.count % 20 === 0) {
                  console.log(Date());
                  setImmediate(printCounters, c.getHost());
                }
            }
            c.startTimer('timeout', 1, 't_' + c.s.count);
        });
        whenStart(function (host) {
          for(var i = 0; i < sidCount; i++) {
            host.post('test', {id: sidCount, sid: i, command: 'start'});
          }
        });
    }   

    d.runAll(['/tmp/redis0.sock', 
              '/tmp/redis1.sock', 
              '/tmp/redis2.sock', 
              '/tmp/redis3.sock', 
              '/tmp/redis4.sock', 
              '/tmp/redis5.sock',
              '/tmp/redis6.sock', 
              '/tmp/redis7.sock'], null, null, null, 12000);
}
``` 
The test fires 11000 timers every second. The test ran without increasing the standard deviation and keeping the average stable. The four cores in my IMac I7 were above 85% utilization. When I change the sid number to 12000, on every iteration, the standard deviation starts increasing and the average becomes lower than expected. Which means the test produces more work than what the system can handle.

@llelf you can currently store any metadata in JSON format by passing `-j` and redirecting the output to a file, but that doesn't work very well and also doesn't download any images while doing that. Using xattrs seems like a good idea so I'll be looking into that.

@Hrxn they state that every user-agent string should look something like `<platform>:<app ID>:<version string> (by /u/<reddit username>)`, which is currently set to `Python:gallery-dl:0.8.4 (by /u/mikf1)`. Take this and replace `gallery-dl` with the name of your registered application and `mikf1` with your own username, but just modifying the given example a bit should work as well.
I'm not sure how strict they are about all of this ("NEVER lie about your user-agent" is written in bold ...) but I wanted to avoid a situation were multiple "applications" use the same user-agent as gallery-dl and they block all of them.

